var e=[{id:`L3_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`괴물들이 전부...... 그림자 속으로 빨려 들어갔어......?`,JPN:`怪物たちが全部……影の中に吸い込まれた……？`,ENG:`The monsters... All of them got swept away into her shadow...`,TWN:`怪物全部……被吸到影子裡面了……？`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`RIVET_ESPR_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L4_1`,type:`dialog`,speaker:`RIVET_ESPR_NULL_NULL`,text:{KOREA:`아니, 저건 잡아 먹었다고 해야 할 걸.`,JPN:`いや、あれは食われたって言うべきだよ。`,ENG:`To be exact, her shadow fed on them.`,TWN:`不，應該說是吃掉了。`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`RIVET_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`네......?`,JPN:`えっ……？`,ENG:`Huh?`,TWN:`什麼……?`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIVET_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`EDEL_ESPR_SHADOW_NULL`,text:{KOREA:`후훗. 오랜만에 섭취하는 지식들이네요.`,JPN:`ふふっ。久しぶりに摂取する知識ですね。`,ENG:`Fu fu. It's been a while since we last fed on these morsels of knowledge.`,TWN:`呵呵，好久沒有攝取知識了呢。`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_SHADOW_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`EDEL_ESPR_SHADOW_NULL`,text:{KOREA:`그렇지만 농축도, 숙성도 제대로 되지 않았다니......`,JPN:`でも濃縮度と熟成度はイマイチですが……`,ENG:`But it's such a shame that they weren't even condensed nor aged properly.`,TWN:`但竟然沒有好好濃縮，也沒有好好熟成……`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_SHADOW_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`EDEL_ESPR_SHADOW_NULL`,text:{KOREA:`에드워드 반 클리프, 35세. 신장 183cm. 1593시간 전 피하 조직에서 작은 종양을 제거하는 수술을 받았고......`,JPN:`エドワード・ヴァン・クリフ、35歳。身長183cm。
1593時間前に皮下組織から小さな腫瘍を摘出する手術を受け……`,ENG:`Edward Van Cliff, 35 years of age. Height, 183 cm. Had a small subcutaneous tumor removed 1593 hours ago.`,TWN:`愛德華•範•克利夫，35歲，身高183cm。1593小時前接受了皮下組織切除小腫瘤的手術……`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_SHADOW_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`EDEL_ESPR_SHADOW_NULL`,text:{KOREA:`엠마 호넷. 여성. Rh- AB형. B랭크 카운터. 카운터 능력은 마찰 계수 감소...... 재능이 있었는데 불운한 최후를 맞이하셨네요.`,JPN:`エマ・ホーネット。女性。Rh- AB型。Bランクカウンター。
カウンター能力は摩擦係数減少……
才能はあったのに不運な最期を迎えたようですね。`,ENG:`Emma Hornet. Female. Blood type, AB negative. Grade B Counter. Specialized in friction control. She was a talented person who met an unfortunate end.`,TWN:`愛瑪•霍納。女性，Rh- AB型血，B級制裁者，制裁能力是減小摩擦係數……明明有才能卻迎來了不幸的結局呢。`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_SHADOW_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`EDEL_ESPR_SHADOW_NULL`,text:{KOREA:`하아...... 겨우 입맛만 돋운 정도네요.`,JPN:`はぁ……前菜にもなりませんね。`,ENG:`*Sigh* That was barely enough to work up the appetite.`,TWN:`唉……勉強能吃吧。`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_SHADOW_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`EDEL_ESPR_SHADOW_NULL`,text:{KOREA:`이 정도로는 모자라요.`,JPN:`この程度では足りません。`,ENG:`This isn't sufficient.`,TWN:`這種程度不夠啊。`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_SHADOW_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`EDEL_ESPR_SHADOW_NULL`,text:{KOREA:`너무 모자라서...... 허기가 가라앉지 않아요.`,JPN:`足りな過ぎて……飢えが満たされません。`,ENG:`This isn't enough to appease our growling stomach.`,TWN:`未免也太少了……飢餓的感覺壓不下去。`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_SHADOW_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`EDEL_ESPR_SHADOW_NULL`,text:{KOREA:`레지나 님, 리벳. 이를 어쩌죠?`,JPN:`レジーナ様、リベット。困ったことに……`,ENG:`Oh no… Miss Regina, Rivet. What do we do?`,TWN:`蕾佳娜大人，里維，這該怎麼辦呢？`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_SHADOW_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`EDEL_ESPR_SHADOW_NULL`,text:{KOREA:`여러분에게서 아주 농밀한......`,JPN:`お二人からとても濃密な……`,ENG:`We can smell a very thick waft of knowledge`,TWN:`兩位身上散發著十分濃郁的……`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_SHADOW_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`EDEL_ESPR_SHADOW_NULL`,text:{KOREA:`지식의 향기가 풍겨요.`,JPN:`知識の香りを感じます。`,ENG:`flowing out of you.`,TWN:`知識香氣啊。`},stage:{bg:`CORRIDOR`,bgm:`THEMA_ESPR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EDEL_ESPR_SHADOW_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};